import React from "react";

import styles from "./CornerBracketCard.module.css";

export interface CornerBracketCardProps
  extends Omit<React.HTMLAttributes<HTMLDivElement>, "title"> {
  title?: React.ReactNode;
  variant?: "default" | "featured";
}

export function CornerBracketCard({
  title,
  variant = "default",
  className = "",
  children,
  ...props
}: CornerBracketCardProps) {
  return (
    <div className={`${styles.card} ${variant === "featured" ? styles.featured : ""} ${className}`.trim()} {...props}>
      <span className={`${styles.corner} ${styles.cornerTopLeft}`} aria-hidden="true" />
      <span className={`${styles.corner} ${styles.cornerTopRight}`} aria-hidden="true" />
      <span className={`${styles.corner} ${styles.cornerBottomLeft}`} aria-hidden="true" />
      <span className={`${styles.corner} ${styles.cornerBottomRight}`} aria-hidden="true" />
      {title ? <div className={styles.title}>{title}</div> : null}
      {children}
    </div>
  );
}

.card {
  position: relative;
  border: 1px solid var(--border-color);
  background: color-mix(in srgb, var(--bg-secondary) 88%, transparent);
  padding: 1rem;
}

.featured {
  border-color: var(--accent-primary);
}

.title {
  margin-bottom: 0.75rem;
  color: var(--text-primary);
  font-family: var(--font-primary);
  font-size: 1rem;
  font-weight: 600;
}

.corner {
  position: absolute;
  width: 18px;
  height: 18px;
  pointer-events: none;
}

.corner::before,
.corner::after {
  content: "";
  position: absolute;
  background: var(--accent-primary);
}

.cornerTopLeft {
  top: -1px;
  left: -1px;
}

.cornerTopLeft::before,
.cornerBottomLeft::before,
.cornerTopRight::before,
.cornerBottomRight::before {
  width: 12px;
  height: 1px;
}

.cornerTopLeft::after,
.cornerBottomLeft::after,
.cornerTopRight::after,
.cornerBottomRight::after {
  width: 1px;
  height: 12px;
}

.cornerTopLeft::before {
  top: 0;
  left: 0;
}

.cornerTopLeft::after {
  top: 0;
  left: 0;
}

.cornerTopRight {
  top: -1px;
  right: -1px;
}

.cornerTopRight::before {
  top: 0;
  right: 0;
}

.cornerTopRight::after {
  top: 0;
  right: 0;
}

.cornerBottomLeft {
  bottom: -1px;
  left: -1px;
}

.cornerBottomLeft::before {
  bottom: 0;
  left: 0;
}

.cornerBottomLeft::after {
  bottom: 0;
  left: 0;
}

.cornerBottomRight {
  bottom: -1px;
  right: -1px;
}

.cornerBottomRight::before {
  bottom: 0;
  right: 0;
}

.cornerBottomRight::after {
  bottom: 0;
  right: 0;
}
